INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Akshardham Temple', 'akshardham-delhi', 'Delhi', 'New Delhi', 'Swaminarayan', 'Mandir', 'A massive Hindu temple complex showcasing 10,000 years of Indian culture. Built entirely of carved sandstone and marble without structural steel, the temple is a Guinness World Record holder.', 'Inaugurated in 2005, the temple was built by BAPS Swaminarayan Sanstha. Over 11,000 artisans and volunteers contributed. The complex features a 3,000-year-old banyan tree from Gujarat and the world''s largest stepwell-style fountain.', 28.6127, 77.2773, 180, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Lakshmi Narayan Temple', 'birla-mandir-delhi', 'Delhi', 'New Delhi', 'Lakshmi Narayan', 'North Indian', 'One of Delhi''s major temples, built by the Birla family. Dedicated to Lakshmi and Narayan (Vishnu), the temple complex also includes shrines for Buddha and other deities.', 'Completed in 1939, the temple was inaugurated by Mahatma Gandhi on the condition that people of all castes would be allowed entry. The temple blends Hindu, Jain, and Mughal architectural styles.', 28.6013, 77.1998, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Kalkaji Mandir', 'kalkaji', 'Delhi', 'New Delhi', 'Kali', 'North Indian', 'An ancient temple dedicated to goddess Kali, located in South Delhi. The temple is a major Shakti Peetha and draws thousands of devotees daily.', 'The temple is believed to be several centuries old, with the current structure dating to the 18th century. It was renovated by the Mughal-era Maratha rulers. The temple is associated with the epic Mahabharata.', 28.5575, 77.2589, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('ISKCON Temple Delhi', 'iskcon-delhi', 'Delhi', 'New Delhi', 'Krishna', 'Modern North Indian', 'One of the largest ISKCON temples in India, featuring a stunning blend of Rajasthani and Odishan architecture. The temple is dedicated to Radha and Krishna.', 'Opened in 1998, the temple was built by the International Society for Krishna Consciousness (ISKCON). The main deities are Sri Sri Radha Parthasarathi. The temple also houses a Vedic museum and cultural center.', 28.5833, 77.2500, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Dakshineswar Kali Temple', 'dakshineswar', 'West Bengal', 'Kolkata', 'Kali', 'Bengal Navaratna', 'A historic temple on the Ganges dedicated to goddess Kali, closely associated with the mystic Sri Ramakrishna Paramahamsa. The temple complex includes 12 shrines.', 'Built in 1855 by Rani Rashmoni, a wealthy philanthropist. Sri Ramakrishna served as the head priest here and his spiritual teachings attracted followers from around the world. The temple is known for its nine-spired architecture.', 22.6550, 88.3575, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Kalighat Kali Temple', 'kalighat', 'West Bengal', 'Kolkata', 'Kali', 'Bengali', 'One of the 51 Shakti Peethas and the most important temple in Kolkata, after which the city is named. The temple features a unique idol of Kali with a golden tongue.', 'The temple dates back centuries, with the current structure rebuilt in 1809. Kolkata''s name is derived from Kalighat. The temple is one of the holiest Shakti Peethas where the toes of Sati''s right foot are believed to have fallen.', 22.5183, 88.3425, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Belur Math', 'belur-math', 'West Bengal', 'Howrah', 'Ramakrishna', 'Syncretic', 'The headquarters of the Ramakrishna Math and Mission, founded by Swami Vivekananda. The temple architecture uniquely blends Hindu, Islamic, Christian, and Buddhist motifs.', 'Founded in 1897 by Swami Vivekananda, the main temple was consecrated in 1938. The architecture symbolizes the unity of all religions. The Math houses the relics of Sri Ramakrishna, Holy Mother Sarada Devi, and Swami Vivekananda.', 22.6325, 88.3583, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Kamakhya Temple', 'kamakhya', 'Assam', 'Guwahati', 'Kamakhya (Shakti)', 'Nilachal', 'One of the oldest and most revered Shakti Peethas, located on the Nilachal Hill. The temple is a major tantric pilgrimage site and is unique for its yoni-shaped sanctum.', 'The temple dates back to the 8th-9th century, with major reconstructions by the Ahom kings in the 16th-17th centuries. It is believed to be where Sati''s yoni (womb) fell. The temple remains closed for three days during Ambubachi Mela.', 26.1667, 91.7167, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Konark Sun Temple', 'konark', 'Odisha', 'Konark', 'Surya (Sun)', 'Kalinga', 'A 13th-century UNESCO World Heritage Site built as a colossal chariot for the Sun God with 12 pairs of stone wheels and seven horses. One of India''s most famous architectural marvels.', 'Built by King Narasimhadeva I of the Eastern Ganga dynasty in 1250 CE. The temple was designed as a 30 m tall chariot. The magnetic lodestone at the top reportedly caused navigational issues for ships, leading to its removal.', 19.8876, 86.0945, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Dilwara Jain Temples', 'dilwara', 'Rajasthan', 'Mount Abu', 'Jain Tirthankaras', 'Maru-Gurjara', 'A group of five Jain temples renowned for their extraordinary marble carvings. The marble work is considered among the finest in the world, with intricate details that appear translucent.', 'Built between the 11th and 13th centuries by the Solanki rulers. The Vimal Vasahi temple (1031 CE) is the oldest. Each temple features exquisite marble ceilings, pillars, and doorways carved from single blocks of marble.', 24.5925, 72.7083, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Ranakpur Jain Temple', 'ranakpur', 'Rajasthan', 'Ranakpur', 'Adinath', 'Maru-Gurjara', 'One of the largest and most important Jain temples, supported by 1,444 uniquely carved marble pillars. No two pillars are the same. The temple is a four-faced design (Chaumukha).', 'Built in the 15th century under the patronage of Rana Kumbha and the guidance of Jain minister Dharna Sah. The temple took 50 years to complete. The design allows sunlight to illuminate every corner.', 25.1158, 73.4717, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Brahma Temple', 'brahma-pushkar', 'Rajasthan', 'Pushkar', 'Brahma', 'Rajput', 'One of the very few temples dedicated to Brahma, the creator god in Hinduism. Located on the banks of the sacred Pushkar Lake, the temple features a distinctive red spire.', 'The original temple is believed to be 2,000 years old, though the current structure dates to the 14th century. Pushkar is the only place in India with a major Brahma temple. The lake is believed to have been formed by a lotus dropped by Brahma.', 26.4917, 74.5500, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Khatu Shyam Temple', 'khatu-shyam', 'Rajasthan', 'Khatu', 'Khatu Shyam (Krishna)', 'Rajput', 'A highly revered temple dedicated to Khatu Shyam, believed to be an incarnation of Krishna. The temple is famous for its miraculous stories and massive devotion during Phalguna Mela.', 'The temple enshrines the head of Barbarika, a warrior from the Mahabharata, who was blessed by Krishna. The current structure was built in the 19th century. The annual fair attracts over a million devotees.', 27.3517, 75.8350, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Mahakaleshwar Temple', 'mahakaleshwar', 'Madhya Pradesh', 'Ujjain', 'Shiva', 'Maratha', 'One of the twelve Jyotirlingas and the only one facing south. The temple is known for its Bhasma Aarti, where the lingam is worshipped with sacred ash from cremation grounds.', 'The temple has been mentioned in the Puranas and was rebuilt by the Maratha ruler Ranoji Scindia in the 18th century. The current five-storeyed structure is adorned with images of various deities. Ujjain is one of the seven sacred cities.', 23.1828, 75.7683, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Bhimashankar Temple', 'bhimashankar', 'Maharashtra', 'Pune', 'Shiva', 'Nagara', 'One of the twelve Jyotirlingas, located in the Sahyadri hills. The temple combines Nagara and Dravidian architectural styles and is surrounded by dense forests.', 'The temple is associated with the legend of Bhima, a demon defeated by Shiva. The current structure dates to the 18th century, built by the Maratha Peshwas. The Shiva lingam is believed to grow with the phases of the moon.', 19.0833, 73.5333, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Trimbakeshwar Temple', 'trimbakeshwar', 'Maharashtra', 'Nashik', 'Shiva', 'Hemisadhak', 'One of the twelve Jyotirlingas, uniquely featuring three lingams representing Brahma, Vishnu, and Shiva. The temple is located near the source of the Godavari River.', 'The temple dates back to the 18th century, built by the third Peshwa. The three lingams are crowned with three faces of the trinity. The nearby Kushavarta tank is where the Godavari originates and is a major pilgrimage spot.', 19.9333, 73.5333, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Grishneshwar Temple', 'grishneshwar', 'Maharashtra', 'Aurangabad', 'Shiva', 'Hemisadhak', 'The twelfth Jyotirlinga, located near the Ellora Caves. It is one of the smallest Jyotirlinga temples but holds immense significance.', 'According to legend, a devotee named Grishneshwari built the temple with her husband''s blessings. The current structure was rebuilt in the 18th century. The temple was destroyed and rebuilt multiple times.', 20.0233, 75.1700, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Mahalakshmi Temple', 'mahalakshmi-kolhapur', 'Maharashtra', 'Kolhapur', 'Lakshmi', 'Hemisadhak', 'One of the three and a half Shakti Peethas and the most important temple of the goddess Lakshmi in Maharashtra. The temple features a unique idol with a mace.', 'The temple is believed to have been built by the Chalukya king Karna in the 7th century. The current structure dates to the 18th century Maratha period. The temple is one of the 108 sacred Shakti sites.', 16.6917, 74.2333, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Vitthal Temple', 'vitthal-pandharpur', 'Maharashtra', 'Pandharpur', 'Vithoba (Krishna)', 'Yadava', 'The most important temple in Maharashtra''s Varkari tradition, dedicated to Vithoba, a form of Krishna. The annual Wari pilgrimage brings millions of devotees.', 'The temple was built in the 13th century by the Yadava king Someshwar. The saints Dnyaneshwar, Tukaram, and Namdev are closely associated with this temple. The icon stands with hands on hips, a unique posture in Hindu iconography.', 17.6833, 75.3333, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Mallikarjuna Temple', 'mallikarjuna-srisailam', 'Andhra Pradesh', 'Srisailam', 'Shiva (Mallikarjuna)', 'Dravidian', 'One of the twelve Jyotirlingas and a Shakti Peetha dedicated to Bhramaramba. The temple is located on a hilltop overlooking the Krishna River.', 'The temple has been mentioned in ancient texts and was patronized by the Vijayanagara Empire, Chalukyas, and other dynasties. The temple has massive gopurams and a 5 m tall Shiva lingam. It is one of the few temples that is both a Jyotirlinga and a Shakti Peetha.', 16.0750, 78.8683, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Srikalahasti Temple', 'srikalahasti', 'Andhra Pradesh', 'Srikalahasti', 'Shiva', 'Dravidian', 'One of the Pancha Bhoota Stalams representing the wind element (Vayu). The temple is renowned for its Vayulingam and its intricate gopuram.', 'The temple was built by the Pallava king in the 5th century and later expanded by the Cholas and Vijayanagara rulers. The temple is associated with the story of a spider, elephant, and snake that worshipped Shiva here. The inner sanctum features a unique lingam.', 13.7500, 79.7000, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Kanaka Durga Temple', 'kanaka-durga', 'Andhra Pradesh', 'Vijayawada', 'Durga', 'Dravidian', 'A major Shakti temple located on the Indrakeeladri hill overlooking the Krishna River. The goddess is depicted in a powerful form with eight arms.', 'The temple is believed to date back to the 2nd century CE, with the current structure rebuilt by the Madhurantaka Chola in the 11th century. The goddess here is Swayambhu (self-manifested). The temple is especially vibrant during the Dasara festival.', 16.5167, 80.6167, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Palani Murugan Temple', 'palani-murugan', 'Tamil Nadu', 'Palani', 'Murugan', 'Dravidian', 'One of the six abodes (Arupadai Veedu) of Lord Murugan, located on a hill 150 m high. The temple is famous for the Palani Kavadi festival.', 'The temple is associated with the legend of Murugan coming to Palani after a dispute with his brother Ganesha. The main deity is believed to be made of navabhashanam (nine poisons), an ancient alchemical compound. Pilgrims carry kavadis decorated with peacock feathers.', 10.4500, 77.5200, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Sabarimala Temple', 'sabarimala', 'Kerala', 'Pathanamthitta', 'Ayyappa', 'Kerala', 'One of the most visited pilgrimage sites in the world, located deep in the Periyar Tiger Reserve. The temple is accessible only by foot through dense forests and hills.', 'The temple is associated with the legend of Ayyappa, the son of Shiva and Mohini. The 41-day Mandala season attracts over 50 million pilgrims annually. Devotees observe strict austerity including celibacy and simple living before the pilgrimage.', 9.4333, 77.0833, 300, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Guruvayur Temple', 'guruvayur', 'Kerala', 'Guruvayur', 'Krishna (Guruvayurappan)', 'Kerala', 'One of the most important Krishna temples in South India, often called the Dwarka of the South. The temple is famous for itså¤§è±¡ procession and strict rituals.', 'The temple is believed to have been established by Brihaspati and Vayu. The current structure dates to the 17th century. The deity is made of a rare stone called Patala Anjana. The temple was attacked by Tipu Sultan in the 18th century.', 10.5917, 76.0417, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Dharmasthala Temple', 'dharmasthala', 'Karnataka', 'Dharmasthala', 'Manjunatha (Shiva)', 'Kerala-Karnataka', 'A unique temple run by a Jain family that serves the Hindu deity Manjunatha. The temple is famous for providing free meals to all visitors regardless of religion.', 'The temple has been managed by the Heggade family for over 20 generations. The presiding deity is a lingam installed by the sage Manjunatha. The temple offers free food to over 10,000 people daily. The annual Rathotsava attracts hundreds of thousands.', 12.9600, 75.4167, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Mookambika Temple', 'kollur-mookambika', 'Karnataka', 'Kollur', 'Mookambika (Shakti)', 'Kerala-Karnataka', 'A powerful Shakti temple located on the banks of the Souparnika River. The goddess is depicted as the unified form of Saraswati, Lakshmi, and Parvati.', 'The temple is believed to have been established by the sage Adi Shankaracharya. The self-manifested (Swayambhu) lingam in the sanctum has a golden line dividing it, representing the union of Shiva and Shakti. The temple is a major center for learning.', 13.8500, 74.8167, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Sringeri Sharada Temple', 'sringeri-sharada', 'Karnataka', 'Sringeri', 'Sharada (Saraswati)', 'Kerala-Karnataka', 'The first of the four mathas established by Adi Shankaracharya, dedicated to the goddess of wisdom. Located on the banks of the Tunga River.', 'Founded in the 8th century by Adi Shankaracharya, this is the most important center of Advaita Vedanta. The Sharada idol is made of sandalwood and is replaced periodically. The matha has an unbroken lineage of gurus.', 13.4167, 75.2500, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Omkareshwar Temple', 'omkareshwar', 'Madhya Pradesh', 'Omkareshwar', 'Shiva', 'Nagara', 'One of the twelve Jyotirlingas, located on an island shaped like the sacred Om symbol in the Narmada River. The temple has two distinct forms of Shiva.', 'The temple is mentioned in the Puranas and was built by the Parmara king in the 11th century. The island itself is shaped like Om. The temple is one of the most beautiful Jyotirlingas due to its river island location.', 22.2500, 76.1500, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Nageshwar Temple', 'nageshwar', 'Gujarat', 'Dwarka', 'Shiva', 'Gujarati', 'One of the twelve Jyotirlingas, located near the Dwarkadhish Temple. The temple features a massive 25 m tall statue of Shiva in a meditating pose.', 'The Jyotirlinga is believed to protect devotees from poison, based on the legend of a demon named Daruka. The temple is also known as Nagnath Temple. The enormous Shiva statue was installed in 2012.', 22.2833, 68.9333, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Chamundeshwari Temple', 'chamundeshwari', 'Karnataka', 'Mysuru', 'Chamundeshwari (Durga)', 'Dravidian', 'A magnificent temple perched atop the Chamundi Hill, overlooking Mysuru. The goddess Chamundeshwari is the patron deity of the Mysuru royal family.', 'The temple dates back to the 12th century with additions by the Vijayanagara rulers and the Wodeyar kings. The goddess is said to have slain the demon Mahishasura here. The 1,000-step staircase to the temple features a massive Nandi statue.', 12.2736, 76.6708, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Murudeshwara Temple', 'murudeshwara', 'Karnataka', 'Murudeshwara', 'Shiva', 'Modern Dravidian', 'A coastal temple featuring the second tallest Shiva statue in the world (37 m). The temple complex includes a massive gopuram tower with ocean views.', 'The temple is associated with the legend of Ravana and the Atma Linga. The modern complex was built in the 20th century, with the giant Shiva statue completed in 2006. The 20-storeyed gopuram offers panoramic views of the Arabian Sea.', 14.0950, 74.4850, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Nellaiappar Temple', 'nellaiappar', 'Tamil Nadu', 'Tirunelveli', 'Shiva', 'Dravidian', 'One of the largest temple complexes in Tamil Nadu, known for its musical pillars and a massive 5-acre temple tank. The temple features exquisite stone carvings.', 'The temple was built over several centuries by the Pandya, Chola, and Vijayanagara rulers. The musical pillars produce different notes when struck. The temple''s Manimandapam is a masterpiece of Vijayanagara architecture.', 8.7317, 77.7567, 120, true, NOW(), NOW())
